from fastapi import FastAPI, HTTPException
from fastapi.responses import StreamingResponse
from pydantic import BaseModel
import json, asyncio

from anthropic import Anthropic

app = FastAPI()
client = Anthropic()

TOOLS = [
    {
        "name": "search_docs",
        "description": "Search the internal documentation for an answer.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "create_ticket",
        "description": "Create a support ticket in the ticketing system.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {"type": "string"},
                "body": {"type": "string"},
                "priority": {"type": "string", "enum": ["low", "medium", "high"]},
            },
            "required": ["title", "body", "priority"],
        },
    },
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == "search_docs":
        return f"Documentation result for '{inputs['query']}': Contact support@example.com for billing issues."
    if name == "create_ticket":
        return json.dumps({"ticket_id": "TKT-9042", "status": "created", **inputs})
    return "unknown tool"

class AgentRequest(BaseModel):
    message: str
    session_id: str | None = None

async def agent_stream(message: str):
    messages = [{"role": "user", "content": message}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=1024,
            system="You are a helpful support agent. Use tools to resolve the user's issue.",
            tools=TOOLS,
            messages=messages,
        )

        # Stream the text blocks as they arrive
        for block in response.content:
            if block.type == "text" and block.text:
                yield f"data: {json.dumps({'type': 'text', 'text': block.text})}\n\n"
                await asyncio.sleep(0)

        if response.stop_reason == "end_turn":
            yield f"data: {json.dumps({'type': 'done'})}\n\n"
            break

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    yield f"data: {json.dumps({'type': 'tool_call', 'name': block.name, 'input': block.input})}\n\n"
                    await asyncio.sleep(0)
                    result = execute_tool(block.name, block.input)
                    yield f"data: {json.dumps({'type': 'tool_result', 'name': block.name, 'result': result})}\n\n"
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })

            messages.append({"role": "assistant", "content": response.content})
            messages.append({"role": "user", "content": tool_results})
        else:
            yield f"data: {json.dumps({'type': 'done'})}\n\n"
            break

@app.post("/agent/chat")
async def chat(req: AgentRequest):
    return StreamingResponse(
        agent_stream(req.message),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )

from fastapi import FastAPI, HTTPException, Depends, Header
import redis, time

app = FastAPI()
r = redis.Redis(host="localhost", port=6379, decode_responses=True)

VALID_KEYS = {"sk-prod-abc123": {"tier": "pro", "rpm": 60}, "sk-free-xyz": {"tier": "free", "rpm": 10}}

def get_api_key(x_api_key: str = Header(...)) -> dict:
    if x_api_key not in VALID_KEYS:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return {"key": x_api_key, **VALID_KEYS[x_api_key]}

def rate_limit(auth: dict = Depends(get_api_key)) -> dict:
    key = f"ratelimit:{auth['key']}"
    now = int(time.time())
    window = now - (now % 60)  # current 1-minute window
    window_key = f"{key}:{window}"
    count = r.incr(window_key)
    if count == 1:
        r.expire(window_key, 120)
    if count > auth["rpm"]:
        raise HTTPException(status_code=429, detail=f"Rate limit: {auth['rpm']} requests/minute")
    return auth

