from fastapi import FastAPI
import asyncio, signal, time

app = FastAPI()
_ready = True
_in_flight: set[asyncio.Task] = set()

@app.get("/health/live")
def liveness() -> dict:
    return {"status": "ok"}

@app.get("/health/ready")
def readiness() -> dict:
    if not _ready:
        from fastapi import Response
        return Response(status_code=503, content="draining")
    return {"status": "ready", "in_flight": len(_in_flight)}

def _register_task(t: asyncio.Task) -> asyncio.Task:
    _in_flight.add(t)
    t.add_done_callback(_in_flight.discard)
    return t

@app.post("/agent/chat")
async def chat(req: dict) -> dict:
    task = _register_task(asyncio.current_task())  # type: ignore[arg-type]
    # ... run agent loop
    return {"reply": "..."}

async def shutdown():
    global _ready
    _ready = False
    # Wait for in-flight tasks to complete (max 30 seconds)
    deadline = time.monotonic() + 30
    while _in_flight and time.monotonic() < deadline:
        await asyncio.sleep(0.5)

# Register SIGTERM handler (called by Kubernetes before SIGKILL)
def handle_sigterm(*_):
    asyncio.get_event_loop().create_task(shutdown())

signal.signal(signal.SIGTERM, handle_sigterm)

