from fastapi import FastAPI
from pydantic import BaseModel
from celery import Celery
import uuid

app = FastAPI()
celery_app = Celery("agent_tasks", broker="redis://localhost:6379/0", backend="redis://localhost:6379/1")

class JobRequest(BaseModel):
    prompt: str
    webhook_url: str | None = None

@celery_app.task(bind=True, max_retries=3)
def run_agent_task(self, job_id: str, prompt: str, webhook_url: str | None):
    from anthropic import Anthropic
    import httpx

    client = Anthropic()
    try:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=2048,
            messages=[{"role": "user", "content": prompt}],
        )
        result = {"job_id": job_id, "status": "complete", "output": response.content[0].text}
    except Exception as exc:
        raise self.retry(exc=exc, countdown=2 ** self.request.retries)

    if webhook_url:
        httpx.post(webhook_url, json=result, timeout=10)
    return result

@app.post("/agent/jobs")
async def submit_job(req: JobRequest) -> dict:
    job_id = str(uuid.uuid4())
    run_agent_task.apply_async(args=[job_id, req.prompt, req.webhook_url], task_id=job_id)
    return {"job_id": job_id, "status": "queued"}

@app.get("/agent/jobs/{job_id}")
async def get_job(job_id: str) -> dict:
    result = celery_app.AsyncResult(job_id)
    if result.ready():
        return {"job_id": job_id, "status": "complete", "result": result.get()}
    return {"job_id": job_id, "status": result.state.lower()}

from anthropic import Anthropic
from dataclasses import dataclass, field

@dataclass
class TokenBudget:
    max_input: int = 50_000
    max_output: int = 10_000
    spent_input: int = 0
    spent_output: int = 0

    def record(self, usage) -> None:
        self.spent_input += usage.input_tokens
        self.spent_output += usage.output_tokens

    @property
    def exhausted(self) -> bool:
        return self.spent_input >= self.max_input or self.spent_output >= self.max_output

    def remaining_output(self) -> int:
        return max(0, self.max_output - self.spent_output)

def run_bounded_agent(prompt: str, budget: TokenBudget | None = None) -> str:
    client = Anthropic()
    if budget is None:
        budget = TokenBudget()

    messages = [{"role": "user", "content": prompt}]
    max_iterations = 10

    for iteration in range(max_iterations):
        if budget.exhausted:
            return "[Agent stopped: token budget exhausted]"

        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=min(512, budget.remaining_output()),
            messages=messages,
        )
        budget.record(response.usage)

        if response.stop_reason == "end_turn":
            return response.content[0].text

        # Handle tool use (abbreviated)
        messages.append({"role": "assistant", "content": response.content})
        # ... execute tools and append results

    return "[Agent stopped: max iterations reached]"

